def sum_of_squares(n:int)->int:
 return sum(i*i for i in range(1,n+1))

def is_palindrome(s:str)->bool:
 s=s.lower()
 return s==s[::-1]

def get_reversed_longer_string(s1,s2):
 longer=get_longer_string(s1,s2)
 return reverse_string(longer)

def get_longer_string(s1,s2):
 return s1 if len(s1)>len(s2) else s2

def reverse_string(s):
 return s[::-1]

def get_average_of_second_elements(numbers):
 if not numbers:
  return 0
 second=[x[1] for x in numbers]
 return sum(second)/len(second)

import statistics

def get_average_of_second_elements(numbers):
 second=get_second(numbers)
 return statistics.mean(second)

def get_second(numbers):
 return [x[1] for x in numbers]
